class InsufficientStockException extends RuntimeException {
    private final String productName;
    private final int requested;
    private final int available;

    InsufficientStockException(String productName, int requested, int available) {
        super(productName + ": requested " + requested + " but only " + available + " available");
        this.productName = productName;
        this.requested = requested;
        this.available = available;
    }

    String getProductName() { return productName; }
    int getRequested() { return requested; }
    int getAvailable() { return available; }
}

public class App {
    public static void main(String[] args) {
        try {
            throw new InsufficientStockException("Keyboard", 5, 2);
        } catch (InsufficientStockException e) {
            System.out.println("InsufficientStockException: " + e.getMessage());
            System.out.println("Product name: " + e.getProductName());
            System.out.println("Requested: " + e.getRequested() + ", Available: " + e.getAvailable());
        }
    }
}

class DatabaseException extends RuntimeException {
    DatabaseException(String message) {
        super(message);
    }
    DatabaseException(String message, Throwable cause) {
        super(message, cause);
    }
}

public class App {
    public static void main(String[] args) {
        // Direct constructor
        try {
            throw new DatabaseException("Connection pool exhausted");
        } catch (DatabaseException e) {
            System.out.println("Direct: " + e.getMessage());
        }

        // Wrapping constructor
        try {
            RuntimeException original = new RuntimeException("timeout after 3000ms");
            throw new DatabaseException("Query failed", original);
        } catch (DatabaseException e) {
            System.out.println("Wrapped: " + e.getMessage() + ": original: " + e.getCause().getMessage());
        }
    }
}

