class LoginException extends RuntimeException {
    LoginException(String msg) { super(msg); }
}

class AccountLockedException extends LoginException {
    private final int lockDuration;
    AccountLockedException(int lockDuration) {
        super("Account locked for " + lockDuration + " minutes");
        this.lockDuration = lockDuration;
    }
    int getLockDuration() { return lockDuration; }
}

class InvalidCredentialsException extends LoginException {
    private final int attempt;
    InvalidCredentialsException(int attempt) {
        super("Invalid credentials (attempt " + attempt + ")");
        this.attempt = attempt;
    }
    int getAttemptNumber() { return attempt; }
}

public class App {
    static void login(String user, String pass, int attempt) {
        if (attempt > 3) throw new AccountLockedException(30);
        if (!pass.equals("correct")) throw new InvalidCredentialsException(attempt);
    }

    public static void main(String[] args) {
        // Locked account
        try { login("aisha", "wrong", 4); }
        catch (AccountLockedException e) { System.out.println("Locked! " + e.getMessage()); }
        catch (InvalidCredentialsException e) { System.out.println("Wrong password (attempt " + e.getAttemptNumber() + " of 3)"); }

        // Wrong password
        try { login("raj", "wrong", 2); }
        catch (AccountLockedException e) { System.out.println("Locked! " + e.getMessage()); }
        catch (InvalidCredentialsException e) { System.out.println("Wrong password (attempt " + e.getAttemptNumber() + " of 3)"); }
    }
}

class OrderException extends RuntimeException {
    private final String orderId;
    private final String reason;
    private final String failedItem;

    OrderException(String orderId, String reason, String failedItem) {
        super(buildMessage(orderId, reason, failedItem));
        this.orderId = orderId;
        this.reason = reason;
        this.failedItem = failedItem;
    }

    private static String buildMessage(String orderId, String reason, String item) {
        String msg = "Order #" + orderId + " failed: " + reason;
        if (item != null) msg += " [item: " + item + "]";
        return msg;
    }

    String getOrderId() { return orderId; }
    String getReason() { return reason; }
    String getFailedItem() { return failedItem; }
}

public class App {
    static void placeOrder(String orderId, String item, boolean inStock, boolean paymentOk) {
        if (!inStock)
            throw new OrderException(orderId, "Item '" + item + "' is out of stock", item);
        if (!paymentOk)
            throw new OrderException(orderId, "Payment declined by bank", null);
    }

    public static void main(String[] args) {
        String[][] tests = {{"ORD-001", "Headphones"}, {"ORD-002", "Mouse"}};
        boolean[] inStock = {false, true};
        boolean[] payOk = {true, false};

        for (int i = 0; i < tests.length; i++) {
            try {
                placeOrder(tests[i][0], tests[i][1], inStock[i], payOk[i]);
            } catch (OrderException e) {
                System.out.println(e.getMessage());
            }
        }
    }
}

