class DataImportException extends RuntimeException {
    private final String failedInput;

    DataImportException(String failedInput, Throwable cause) {
        super("Failed to import '" + failedInput + "'", cause);
        this.failedInput = failedInput;
    }

    String getFailedInput() { return failedInput; }
}

public class App {
    static String importRecord(String dateStr, String amountStr) {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
        sdf.setLenient(false);
        try {
            sdf.parse(dateStr);  // throws ParseException for invalid dates
            double amount = Double.parseDouble(amountStr);
            return "₹" + amount + " on " + dateStr;
        } catch (ParseException e) {
            throw new DataImportException(dateStr, e);
        }
    }

    public static void main(String[] args) {
        String[] dates = {"2024-01-15", "2024-99-99"};
        for (String d : dates) {
            try {
                System.out.println("Imported: " + importRecord(d, "5000"));
            } catch (DataImportException e) {
                System.out.println("DataImportException: " + e.getMessage() +
                    " — caused by: " + e.getCause().getMessage());
            }
        }
    }
}

