import java.util.*;

class InventoryException extends RuntimeException {
    InventoryException(String msg) { super(msg); }
}

class ProductNotFoundException extends InventoryException {
    private final String productId;
    ProductNotFoundException(String productId) {
        super("Product '" + productId + "' not found");
        this.productId = productId;
    }
    String getProductId() { return productId; }
}

class InsufficientQuantityException extends InventoryException {
    private final String productId;
    private final int requested, available;
    InsufficientQuantityException(String productId, int requested, int available) {
        super(productId + ": requested " + requested + ", only " + available + " available");
        this.productId = productId; this.requested = requested; this.available = available;
    }
}

class Inventory {
    private Map<String, Integer> stock = new HashMap<>();

    Inventory() {
        stock.put("Mouse", 35);
        stock.put("Keyboard", 12);
    }

    void remove(String productId, int qty) {
        Integer current = stock.get(productId);
        if (current == null) throw new ProductNotFoundException(productId);
        if (current < qty)   throw new InsufficientQuantityException(productId, qty, current);
        stock.put(productId, current - qty);
        System.out.println("Removed " + qty + " x " + productId + " (" + (current - qty) + " left)");
    }
}

public class App {
    public static void main(String[] args) {
        Inventory inv = new Inventory();
        String[][] tests = {{"Mouse","3"},{"TABLET-01","1"},{"Mouse","50"}};
        for (String[] t : tests) {
            try {
                inv.remove(t[0], Integer.parseInt(t[1]));
            } catch (ProductNotFoundException e) {
                System.out.println("ProductNotFoundException: " + e.getMessage());
            } catch (InsufficientQuantityException e) {
                System.out.println("InsufficientQuantityException: " + e.getMessage());
            }
        }
    }
}

class ValidationException extends RuntimeException {
    ValidationException(String message) { super(message); }
}

public class App {
    static void validateBad(String value) {
        if (!value.contains("@")) throw new ValidationException("invalid");
    }

    static void validateGood(String userId, String field, String value) {
        if (!value.contains("@"))
            throw new ValidationException(
                "User " + userId + ": " + field + " '" + value + "' is not valid (must contain @)");
    }

    public static void main(String[] args) {
        try { validateBad("notAnEmail"); }
        catch (ValidationException e) { System.out.println("Bad: " + e.getMessage()); }

        try { validateGood("ID-42", "email", "notAnEmail"); }
        catch (ValidationException e) { System.out.println("Good: " + e.getMessage()); }
    }
}

class OrderException extends RuntimeException {
    OrderException(String msg) { super(msg); }
}

class CartException extends OrderException {
    CartException(String msg) { super(msg); }
}

class OutOfStockException extends CartException {
    private final String itemId;
    private final int requested, available;
    OutOfStockException(String itemId, int req, int avail) {
        super("Item '" + itemId + "' requested " + req + " but only " + avail + " in stock");
        this.itemId = itemId; this.requested = req; this.available = avail;
    }
    String getItemId() { return itemId; }
}

class CheckoutException extends OrderException {
    CheckoutException(String msg) { super(msg); }
}

class PaymentDeclinedException extends CheckoutException {
    private final String cardLast4, declineReason;
    PaymentDeclinedException(String last4, String reason) {
        super("Card ending " + last4 + " declined: " + reason);
        this.cardLast4 = last4; this.declineReason = reason;
    }
    String getCardLast4() { return cardLast4; }
    String getDeclineReason() { return declineReason; }
}

class AddressUnserviceableException extends CheckoutException {
    private final String pincode;
    AddressUnserviceableException(String pin) {
        super("Pincode " + pin + " is not serviceable");
        this.pincode = pin;
    }
}

public class App {
    public static void main(String[] args) {
        OrderException[] errors = {
            new OutOfStockException("MOUSE-01", 3, 1),
            new PaymentDeclinedException("4242", "insufficient_funds"),
            new AddressUnserviceableException("999999"),
            new CartException("Cart validation failed")
        };

        for (OrderException e : errors) {
            if (e instanceof OutOfStockException ose)
                System.out.println("OutOfStockException: " + ose.getMessage());
            else if (e instanceof PaymentDeclinedException pde)
                System.out.println("PaymentDeclinedException: " + pde.getMessage());
            else if (e instanceof AddressUnserviceableException ae)
                System.out.println("AddressUnserviceableException: " + ae.getMessage());
            else
                System.out.println("Base CartException: " + e.getMessage());
        }
    }
}

import java.util.*;

class ApiException extends RuntimeException {
    private final int httpStatus;
    ApiException(int status, String msg) { super(msg); this.httpStatus = status; }
    int getHttpStatus() { return httpStatus; }
}

class NotFoundException extends ApiException {
    private final String resourceId;
    NotFoundException(String resourceId) {
        super(404, "Resource '" + resourceId + "' not found");
        this.resourceId = resourceId;
    }
    String getResourceId() { return resourceId; }
}

class UnauthorizedException extends ApiException {
    UnauthorizedException() { super(401, "Authentication required"); }
}

class ValidationException extends ApiException {
    private final List<String> fieldErrors;
    ValidationException(List<String> errors) {
        super(400, "Field errors: " + errors);
        this.fieldErrors = errors;
    }
    List<String> getFieldErrors() { return fieldErrors; }
}

public class App {
    static void process(String action) {
        switch (action) {
            case "ok"         -> System.out.println("200: OK — User profile loaded");
            case "notfound"   -> throw new NotFoundException("user-999");
            case "auth"       -> throw new UnauthorizedException();
            case "validation" -> throw new ValidationException(List.of("name is required", "email is invalid"));
        }
    }

    static String handleRequest(String action) {
        try {
            process(action);
            return null;
        } catch (NotFoundException e) {
            return e.getHttpStatus() + ": NOT FOUND — " + e.getMessage();
        } catch (UnauthorizedException e) {
            return e.getHttpStatus() + ": UNAUTHORIZED — " + e.getMessage();
        } catch (ValidationException e) {
            return e.getHttpStatus() + ": BAD REQUEST — Field errors: " + e.getFieldErrors();
        } catch (ApiException e) {
            return e.getHttpStatus() + ": ERROR — " + e.getMessage();
        }
    }

    public static void main(String[] args) {
        String[] actions = {"ok", "notfound", "auth", "validation"};
        for (String a : actions) {
            String result = handleRequest(a);
            if (result != null) System.out.println(result);
        }
    }
}

class RazorpayException extends RuntimeException {
