    PaymentException(String paymentId, String errorCode, String desc) {
        super(errorCode, desc);
        this.paymentId = paymentId;
    }
    String getPaymentId() { return paymentId; }
}

class CardDeclinedException extends PaymentException {
    private final String declineCode;
    CardDeclinedException(String paymentId, String declineCode) {
        super(paymentId, "CARD_DECLINED", "Card declined: " + declineCode);
        this.declineCode = declineCode;
    }
    String getDeclineCode() { return declineCode; }
}

class PaymentGatewayException extends PaymentException {
    private final String gatewayId;
    PaymentGatewayException(String paymentId, String gatewayId) {
        super(paymentId, "GATEWAY_ERROR", "Gateway " + gatewayId + " unreachable");
        this.gatewayId = gatewayId;
    }
    String getGatewayId() { return gatewayId; }
}

class RefundException extends RazorpayException {
    private final String refundId, reason;
    RefundException(String refundId, String reason) {
        super("REFUND_FAILED", reason);
        this.refundId = refundId; this.reason = reason;
    }
    String getReason() { return reason; }
}

public class App {
    static double processPayment(String id, double amount, String scenario) {
        switch (scenario) {
            case "decline" -> throw new CardDeclinedException(id, "insufficient_funds");
            case "gateway" -> throw new PaymentGatewayException(id, "HDFC-GW");
            default -> { return amount; }
        }
    }

    static void processRefund(String refundId, String scenario) {
        if ("expired".equals(scenario)) throw new RefundException(refundId, "Refund deadline exceeded");
    }

    public static void main(String[] args) {
        // PAY-001 success
        try {
            double amt = processPayment("PAY-001", 5000, "ok");
            System.out.println("PAY-001 success: ₹" + amt);
        } catch (CardDeclinedException e) {
            System.out.println(e.getPaymentId() + " DECLINED (" + e.getDeclineCode() + "): Ask user to add funds or try another card");
        } catch (PaymentGatewayException e) {
            System.out.println(e.getPaymentId() + " GATEWAY ERROR (" + e.getGatewayId() + "): Retry in 30s or contact support");
        }

        // PAY-002 declined
        try {
            processPayment("PAY-002", 2000, "decline");
        } catch (CardDeclinedException e) {
            System.out.println(e.getPaymentId() + " DECLINED (" + e.getDeclineCode() + "): Ask user to add funds or try another card");
        } catch (PaymentGatewayException e) {
            System.out.println(e.getPaymentId() + " GATEWAY ERROR (" + e.getGatewayId() + "): Retry in 30s or contact support");
        }

        // PAY-003 gateway error
        try {
            processPayment("PAY-003", 1500, "gateway");
        } catch (CardDeclinedException e) {
            System.out.println(e.getPaymentId() + " DECLINED (" + e.getDeclineCode() + "): Ask user to add funds or try another card");
        } catch (PaymentGatewayException e) {
            System.out.println(e.getPaymentId() + " GATEWAY ERROR (" + e.getGatewayId() + "): Retry in 30s or contact support");
        }

        // REFUND-001
        try {
            processRefund("REFUND-001", "expired");
        } catch (RefundException e) {
            System.out.println("REFUND-001 FAILED: " + e.getReason());
        }
    }
}
